<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import PageHeader from '@/components/PageHeader.vue'
import StatusTag from '@/components/StatusTag.vue'
import type { Batch, MerkleRootResult, Project, Student, Template } from '@/types'
import { createBatch, deleteBatch, generateMerkleRoot, getBatches, getMerkleRoot, updateBatch } from '@/api/batches'
import { evidenceBatch } from '@/api/certificates'
import { getStudents } from '@/api/students'
import { getProjects } from '@/api/projects'
import { getTemplates } from '@/api/templates'
const loading=ref(false),dialog=ref(false),detail=ref(false),rows=ref<Batch[]>([]),total=ref(0),current=ref<Batch>(),students=ref<Student[]>([]),projects=ref<Project[]>([]),templates=ref<Template[]>([]),rootLoading=ref<number>(),rootQueryLoading=ref<number>(),roots=ref<Record<number,MerkleRootResult>>({}),evidenceLoading=ref<number>()
const query=reactive({current:1,size:10,keyword:'',status:''})
const form=reactive<Batch & {student_ids:number[]}>({batch_id:0,batch_no:'',batch_name:'',project_id:0,project_name:'',template_id:0,student_count:0,generated:0,evidenced:0,student_ids:[],status:'DRAFT'})
async function load(){loading.value=true;try{const p=await getBatches(query);rows.value=p.records;total.value=p.total;await Promise.allSettled(p.records.map(async row=>{const result=await getMerkleRoot(row.batch_id);if(result)roots.value[row.batch_id]=result;else delete roots.value[row.batch_id]}))}catch{rows.value=[]}finally{loading.value=false}}
function reset(){query.keyword='';query.status='';query.current=1;load()}
function progressPercent(done:number,total:number){if(!total)return 0;return Math.min(100,Math.max(0,Math.round(done/total*100)))}
async function open(row?:Batch){Object.assign(form,row?{...row,project_id:row.project_id||0,student_ids:[]}:{batch_id:0,batch_no:'',batch_name:'',project_id:0,project_name:'',template_id:0,student_count:0,generated:0,evidenced:0,student_ids:[],status:'DRAFT'});const jobs:Promise<unknown>[]=[];if(!projects.value.length)jobs.push(getProjects({current:1,size:100,keyword:'',status:'ACTIVE'}).then(page=>{projects.value=page.records}));if(!templates.value.length)jobs.push(getTemplates({current:1,size:100,keyword:'',status:'ENABLED'}).then(page=>{templates.value=page.records}));if(!row&&!students.value.length)jobs.push(getStudents({current:1,size:100,keyword:'',status:''}).then(page=>{students.value=page.records}));await Promise.all(jobs);dialog.value=true}
function selectProject(projectId:number){const project=projects.value.find(item=>item.id===projectId);form.project_name=project?.name||''}
async function save(){if(!form.batch_name||!form.project_id||!form.project_name)return ElMessage.warning('请选择实训项目');if(!form.template_id)return ElMessage.warning('请选择证书模板');if(!form.batch_id&&!form.student_ids.length)return ElMessage.warning('请选择至少一名学生');if(form.batch_id)await updateBatch(form.batch_id,form);else await createBatch({batch_name:form.batch_name,project_id:form.project_id,project_name:form.project_name,template_id:form.template_id,student_ids:form.student_ids});ElMessage.success('保存成功');dialog.value=false;load()}
async function remove(row:Batch){await ElMessageBox.confirm(`确认删除批次“${row.batch_name}”吗？`,'删除批次',{type:'warning'});await deleteBatch(row.batch_id);ElMessage.success('删除成功');load()}
function canEvidence(row:Batch){return row.generated>0&&row.evidenced<row.generated}
async function evidence(row:Batch){if(evidenceLoading.value||!canEvidence(row))return;evidenceLoading.value=row.batch_id;try{await evidenceBatch(row.batch_id);ElMessage.success('批量存证完成');await load()}finally{evidenceLoading.value=undefined}}
async function createRoot(row:Batch){if(rootLoading.value)return;rootLoading.value=row.batch_id;try{const existing=await getMerkleRoot(row.batch_id);if(existing){roots.value[row.batch_id]=existing;current.value=row;detail.value=true;ElMessage.info('该批次已生成 Merkle Root，已打开现有结果');return}await ElMessageBox.confirm('生成后 Root 将作为历史事实保存，不能覆盖或删除。确认继续吗？','生成 Merkle Root',{type:'warning'});const result=await generateMerkleRoot(row.batch_id);roots.value[row.batch_id]=result;current.value=row;detail.value=true;ElMessage.success(result.tx_hash?'Merkle Root 已生成并写入测试链':'Merkle Root 已生成，本次未返回链上交易哈希')}finally{rootLoading.value=undefined}}
async function show(row:Batch){current.value=row;detail.value=true;rootQueryLoading.value=row.batch_id;try{const result=await getMerkleRoot(row.batch_id);if(result)roots.value[row.batch_id]=result;else delete roots.value[row.batch_id]}finally{if(rootQueryLoading.value===row.batch_id)rootQueryLoading.value=undefined}}
function copy(value?:string){if(value){navigator.clipboard.writeText(value);ElMessage.success('已复制')}}
onMounted(load)
</script>
<template><div><PageHeader title="证书批次" description="组织批量签发、批量存证与 P2 Merkle Root"><el-button type="primary" @click="open()">创建批次</el-button></PageHeader><section class="panel"><div class="toolbar"><el-input v-model="query.keyword" placeholder="批次编号、名称或项目" clearable style="width:280px"/><el-select v-model="query.status" placeholder="状态" clearable style="width:150px"><el-option v-for="s in ['DRAFT','IMPORTED','GENERATED','EVIDENCED','COMPLETED','CANCELLED']" :key="s" :label="s" :value="s"/></el-select><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button></div><el-table v-loading="loading" :data="rows" empty-text="暂无批次数据"><el-table-column prop="batch_no" label="批次编号" min-width="170"/><el-table-column prop="batch_name" label="批次名称" min-width="190"/><el-table-column prop="project_name" label="实训项目" min-width="180"/><el-table-column prop="student_count" label="学生数" width="80"/><el-table-column label="生成进度" min-width="120"><template #default="s"><el-progress :percentage="progressPercent(s.row.generated,s.row.student_count)"/></template></el-table-column><el-table-column label="存证进度" min-width="120"><template #default="s"><el-progress :percentage="progressPercent(s.row.evidenced,s.row.student_count)" color="#059669"/></template></el-table-column><el-table-column label="状态" width="105"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column label="操作" min-width="330"><template #default="s"><el-button link type="primary" @click="show(s.row)">详情</el-button><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="success" :disabled="!canEvidence(s.row)" :loading="evidenceLoading===s.row.batch_id" :title="s.row.generated===0?'请先生成证书':'该批次已全部存证'" @click="evidence(s.row)">{{s.row.evidenced>=s.row.generated&&s.row.generated>0?'已全部存证':'批量存证'}}</el-button><el-button link type="warning" :loading="rootLoading===s.row.batch_id" @click="roots[s.row.batch_id]?show(s.row):createRoot(s.row)">{{roots[s.row.batch_id]?'查看Root':'生成Root'}}</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-dialog v-model="dialog" :title="form.batch_id?'编辑批次':'创建批次'" width="560"><el-form label-position="top"><el-form-item label="批次名称" required><el-input v-model="form.batch_name"/></el-form-item><el-form-item label="实训项目" required><el-select v-model="form.project_id" filterable placeholder="请选择真实项目" style="width:100%" @change="selectProject"><el-option v-for="project in projects" :key="project.id" :label="project.name" :value="project.id"/></el-select></el-form-item><el-form-item label="证书模板" required><el-select v-model="form.template_id" filterable placeholder="请选择证书模板" style="width:100%"><el-option v-for="item in templates" :key="item.template_id" :label="item.name" :value="item.template_id"/></el-select></el-form-item><el-form-item v-if="!form.batch_id" label="选择学生" required><el-select v-model="form.student_ids" multiple filterable collapse-tags style="width:100%"><el-option v-for="student in students" :key="student.student_id" :label="`${student.student_no} ${student.student_name}`" :value="student.student_id"/></el-select></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog><el-drawer v-model="detail" title="批次详情" size="620"><div v-if="current" class="detail-list"><div><span>批次编号</span><b>{{current.batch_no}}</b></div><div><span>批次名称</span><b>{{current.batch_name}}</b></div><div><span>项目</span><b>{{current.project_name}}</b></div><div><span>学生数</span><b>{{current.student_count}}</b></div></div><template v-if="current"><h3 class="evidence-title">存证信息（P2）</h3><div v-loading="rootQueryLoading===current.batch_id" class="root-section"><el-empty v-if="!roots[current.batch_id]" description="该批次尚未生成 Merkle Root" :image-size="70"><el-button type="primary" :loading="rootLoading===current.batch_id" @click="createRoot(current)">生成 Merkle Root</el-button></el-empty><div v-else class="root-info"><el-tag :type="roots[current.batch_id].tx_hash?'success':'info'">{{roots[current.batch_id].tx_hash?'测试链已返回交易哈希':'本地Root'}}</el-tag><dl><dt>Root编号</dt><dd>{{roots[current.batch_id].root_no}}</dd><dt>Merkle Root</dt><dd @click="copy(roots[current.batch_id].merkle_root)">{{roots[current.batch_id].merkle_root}}</dd><dt>Root链哈希</dt><dd @click="copy(roots[current.batch_id].current_root_hash)">{{roots[current.batch_id].current_root_hash}}</dd><dt>证书叶子数</dt><dd>{{roots[current.batch_id].leaf_count}}</dd><dt>排序 / 奇数叶规则</dt><dd>{{roots[current.batch_id].leaf_order_rule}} / {{roots[current.batch_id].odd_leaf_rule}}</dd><dt>交易哈希</dt><dd v-if="roots[current.batch_id].tx_hash" @click="copy(roots[current.batch_id].tx_hash)">{{roots[current.batch_id].tx_hash}}</dd><dd v-else>本地 Root 暂无链上交易哈希</dd></dl></div></div></template></el-drawer></div></template>
<style scoped>.evidence-title{margin:28px 0 14px;border-top:1px solid #edf0f4;padding-top:22px}.root-section{min-height:180px}.root-info dl{margin-top:16px}.root-info dt{font-size:12px;color:#7d8a9d;margin-top:14px}.root-info dd{margin:5px 0 0;font:12px Consolas,monospace;word-break:break-all;cursor:pointer}.root-info dd:last-child{cursor:default}</style>


